class Solution:
    def flipLights(self, n: int, presses: int) -> int:
        if presses == 0:
            return 1
        if n == 1:
            return 2
        if n == 2:
            if presses == 1:
                return 3
            else:
                return 4
        if presses == 1:
            return 4
        if presses == 2:
            return 7
        return 8
